        "id": "01f0e5926e411b7091ca77b24024cc8f",
        "question": [
          "how many approved recurring deposits we had the last half a year and what was the total AmountInUSD? \n",
          "show me that on monthly basis.\n",
          "Show me also the total count of recurring deposits and the sum of AmountInUSD on the last half a year\n",
          "show me different bar charts for recurring deposit count and total amount"
        ],
        "answer": [
          {
            "format": "SQL",
            "content": [
              "WITH recurring_approved_deposits AS (\r\n",
              "  SELECT\r\n",
              "    d.DepositID,\r\n",
              "    d.PaymentDate,\r\n",
              "    d.Amount * d.ExchangeRate AS AmountInUSD\r\n",
              "  FROM\r\n",
              "    `main`.`billing`.`bronze_etoro_billing_deposit` d\r\n",
              "      JOIN `main`.`general`.`bronze_etoro_dictionary_paymentstatus` ps\r\n",
              "        ON d.PaymentStatusID = ps.PaymentStatusID\r\n",
              "      JOIN `main`.`general`.`bronze_etoro_dictionary_deposittype` dt\r\n",
              "        ON d.DepositTypeID = dt.DepositTypeID\r\n",
              "  WHERE\r\n",
              "    ps.Name = 'Approved'\r\n",
              "    AND dt.DepositType = 'Recurring'\r\n",
              "    AND d.PaymentDate >= DATE_TRUNC('MONTH', DATEADD(MONTH, -6, CURRENT_DATE()))\r\n",
              "    AND d.PaymentDate IS NOT NULL\r\n",
              "    AND d.Amount IS NOT NULL\r\n",
              "    AND d.ExchangeRate IS NOT NULL\r\n",
              ")\r\n",
              "SELECT\r\n",
              "  DATE_TRUNC('MONTH', PaymentDate) AS month,\r\n",
              "  COUNT(*) AS recurring_deposit_count,\r\n",
              "  SUM(AmountInUSD) AS total_amount_in_usd,\r\n",
              "  CASE\r\n",
              "    WHEN GROUPING(DATE_TRUNC('MONTH', PaymentDate)) = 1 THEN 'Total'\r\n",
              "    ELSE 'Monthly'\r\n",
              "  END AS aggregation_level\r\n",
              "FROM\r\n",
              "  recurring_approved_deposits\r\n",
              "GROUP BY\r\n",
              "  GROUPING SETS ((DATE_TRUNC('MONTH', PaymentDate)), ())\r\n",
              "ORDER BY\r\n",
              "  aggregation_level DESC,\r\n",
              "  month;"
            ]
          }
        ]
      },
