        "id": "01f0e182b049171db1dac6eb33648af1",
        "question": [
          "How did the average weekly volume of Global First Time Deposits (FTDs) on the IBAN (AccountTypeId 3) and Trading (AccountTypeId 1) platforms in Australia change before and after the deposit screen update on November 16th, 2025, starting from September 1st, 2025?"
        ],
        "answer": [
          {
            "format": "SQL",
            "content": [
              "WITH ftds AS (\r\n",
              "  SELECT\r\n",
              "    ftd.`AccountTypeId`,\r\n",
              "    CASE\r\n",
              "      WHEN ftd.`FtdDate` < '2025-11-16' THEN 'Before'\r\n",
              "      ELSE 'After'\r\n",
              "    END AS period,\r\n",
              "    DATE_TRUNC('WEEK', ftd.`FtdDate`) AS week\r\n",
              "  FROM\r\n",
              "    `main`.`bi_db`.`bronze_customerfinancedb_customer_globalftds` ftd\r\n",
              "      JOIN main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_customer_masked cust\r\n",
              "        ON ftd.`Gcid` = cust.`GCID`\r\n",
              "      JOIN `main`.`general`.`bronze_etoro_dictionary_country` country\r\n",
              "        ON cust.`CountryID` = country.`CountryID`\r\n",
              "  WHERE\r\n",
              "    country.`Name` = 'Australia'\r\n",
              "    AND ftd.`FtdDate` >= '2025-09-01'\r\n",
              "    AND ftd.`FtdDate` IS NOT NULL\r\n",
              "    AND cust.`CountryID` IS NOT NULL\r\n",
              ")\r\n",
              "SELECT\r\n",
              "  COALESCE(CAST(AccountTypeId AS STRING), 'All') AS AccountTypeId,\r\n",
              "  period,\r\n",
              "  AVG(num_ftds) AS avg_ftds_per_week\r\n",
              "FROM\r\n",
              "  (\r\n",
              "    SELECT\r\n",
              "      AccountTypeId,\r\n",
              "      period,\r\n",
              "      week,\r\n",
              "      COUNT(*) AS num_ftds\r\n",
              "    FROM\r\n",
              "      ftds\r\n",
              "    WHERE\r\n",
              "      AccountTypeId IN (1, 3)\r\n",
              "      OR AccountTypeId IS NOT NULL\r\n",
              "    GROUP BY\r\n",
              "      AccountTypeId,\r\n",
              "      period,\r\n",
              "      week\r\n",
              "    UNION ALL\r\n",
              "    SELECT\r\n",
              "      NULL AS AccountTypeId,\r\n",
              "      period,\r\n",
              "      week,\r\n",
              "      COUNT(*) AS num_ftds\r\n",
              "    FROM\r\n",
              "      ftds\r\n",
              "    GROUP BY\r\n",
              "      period,\r\n",
              "      week\r\n",
              "  ) grouped\r\n",
              "GROUP BY\r\n",
              "  AccountTypeId,\r\n",
              "  period\r\n",
              "ORDER BY\r\n",
              "  AccountTypeId,\r\n",
              "  period;"
            ]
          }
        ]
